const EXPECTED_STATE_HASH = "412721506409658fd0e24b19dabfed2c593ea21c326ccb12e8ab70aaa6031ee6";

// Hash a final GameState for a compact drift signature. Stable across runs
// because the reducer always builds state objects with the same key
// insertion order for the same code path.
function hashState(state) {
  return crypto.createHash("sha256").update(JSON.stringify(state)).digest("hex");
}

// Replay RECORDED_ACTIONS from a fresh REPLAY_SEED initial state and return
// the final GameState.
function replayRecordedActions() {
  let state = createInitialGameState(REPLAY_SEED);
  for (const action of RECORDED_ACTIONS) {
    state = applyAction(state, action);
  }
  return state;
}

test("replaying the recorded action list reaches the scoring phase", () => {
  const state = replayRecordedActions();
  assert.equal(state.phase.kind, "scoring");
  assert.equal(state.round, 6);
});

test("two independent replays of the same action list produce deep-equal final states", () => {
  const first = replayRecordedActions();
  const second = replayRecordedActions();
  assert.deepEqual(first, second);
});

test("the recorded action list replays to the pinned fixture hash (schema-drift guard)", () => {
  const state = replayRecordedActions();
  assert.equal(hashState(state), EXPECTED_STATE_HASH);
});
